import React from 'react';
import './homePage.css'; // Importer le fichier CSS local si nécessaire

const HomePage = () => {
  return (
    <div className="container">
      <header>
        <h1>Contact Christian Dupont</h1>
      </header>
      <section>
        <div className="bubbles-container">
          {/* Utiliser l'image importée ici */}
          <img
            className="bubbles"
            src={bullesDevImage}
            alt="Les bulles du dev"
          />
        </div>
      </section>
    </div>
  );
};

export default HomePage;
